snippets.C0680:
# C0680 · Uso de teclado (keydown/atajos) (Intermedio, UI/Entrada)
# Bash: read -n1 (una tecla, sin Enter)
solve() {
  echo "Presiona WASD (q para salir):"
  while true; do
    IFS= read -r -n1 k
    case "$k" in
      q) break ;;
      w|W) echo "Mover: arriba" ;;
      s|S) echo "Mover: abajo" ;;
      a|A) echo "Mover: izquierda" ;;
      d|D) echo "Mover: derecha" ;;
    esac
  done
}
